    *Revised Evaluator*:
    ```typescript
    function evaluate(tokens: any[]) {
        const values: number[] = [];
         const ops: any[] = [];

        const precedence: Record<string, number> = {
            'UNARY_PLUS': 3,
            'UNARY_MINUS': 3,
            'MUL': 2,
            'DIV': 2,
            'PLUS': 1,
            'MINUS': 1
        };

        for (let i = 0; i < tokens.length; i++) {
            const token = tokens[i];
            const prev = i > 0 ? tokens[i-1] : null;

            if (token.type === 'NUMBER') {
                values.push(token.value);
            } else if (token.type === 'LPAREN') {
                ops.push(token);
            } else if (token.type === 'RPAREN') {
                while (ops.length > 0 && ops[ops.length - 1].type !== 'LPAREN') {
                    applyOp(values, ops);
                }
                ops.pop(); // remove LPAREN
            } else {
                // Determine if unary or binary
                let type = token.type;
                const isUnary = (type === 'PLUS' || type === 'MINUS') &&
                    (prev === null || prev.type === 'LPAREN' || 
                     ['PLUS', 'MINUS', 'MUL', 'DIV'].includes(prev.type));

                if (isUnary) {
                    type = (type === 'PLUS') ? 'UNARY_PLUS' : 'UNARY_MINUS';
                }

                while (ops.length > 0 && 
                       ops[ops.length - 1].type !== 'LPAREN' &&
                       precedence[ops[ops.length - 1].type] >= precedence[type]]) {
                    applyOp(values, ops);
                }
                ops.push({ type, value: token.value });
            }
        }

        while (ops.length > 0) {
            applyOp(values, ops);
        }
        return values[0];
    }

    function applyOp(values: number[], ops: any[]) {
        const op = ops.pop()!;
         if (op.type === 'UNARY_PLUS' || op.type === 'UNARY_MINUS') {
            const val = values.pop()!;
            values.push(op.type === 'UNARY_PLUS' ? val : -val);
        } else {
            const b = values.pop()!;
            const a = values.pop()!;
            if (op.type === 'PLUS') values.push(a + b);
            else if (op.type === 'MINUS') values.push(a - b);
            else if (op.type === 'MUL') values.push(a * b);
            else if (op.type === 'DIV') values.push(Math.trunc(a / b));
        }
    }
